import { Grid, CircularProgress, Dialog, DialogContent, DialogActions } from '@mui/material';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import Button from '@mui/material/Button';
import IconButton from '@mui/material/IconButton';
import AttachmentIcon from '@mui/icons-material/Attachment';
import InfoOutlinedIcon from '@mui/icons-material/InfoOutlined';
import MaterialTableWrapper from '../../../../../common/tableComponents/MaterialTableWrapper';

interface Props {
	toggleModal: () => void;
	claim: any;
}

function ClaimDetails({ toggleModal, claim }: Props) {
	const { t } = useTranslation('customerClaims');
	const [pageNo, setPageNo] = useState<number>(0);
	const [pageSize, setPageSize] = useState<number>(5);
	const [, setClickedRowData] = useState(null);
	const [count] = useState(100);
	const [isOpenNewMethod, setOpenNewMethodModal] = useState(false);
	const [isLoading, setIsLoading] = useState(false);
	const [images, setImages] = useState<string[]>([]);
	const [isPreviewOpen, setIsPreviewOpen] = useState(false);
	const [selectedImage, setSelectedImage] = useState<string | null>(null);

	const toggleNewAdvertisementModal = () => setOpenNewMethodModal(!isOpenNewMethod);

	const handlePageChange = (page: number) => {
		setPageNo(page);
	};

	const handlePageSizeChange = (pageSize: number) => {
		setPageSize(pageSize);
	};

	const tableRowViewHandler = (rowData) => {
		setClickedRowData(rowData);
		toggleNewAdvertisementModal();
	};

	const tableRowEditHandler = () => {};
	const tableRowDeleteHandler = () => {};

	const handleAttachDocument = (rowData) => {
		setIsLoading(true);
		const loadedImages = rowData.attachDocument.images || [];
		setImages(loadedImages);
		setIsLoading(false);
	};

	const handleImageClick = (image: string) => {
		setSelectedImage(image);
		setIsPreviewOpen(true);
	};

	const closePreview = () => {
		setIsPreviewOpen(false);
		setSelectedImage(null);
	};

	const tableColumns = [
		{
			title: t('CLAIM_ID'),
			field: 'claimId'
		},
		{
			title: t('PRODUCT_ID'),
			field: 'productId'
		},
		{
			title: t('PRODUCT_NAME'),
			field: 'productName'
		},
		{ title: t('SIZE'), field: 'size' },
		{
			title: t('QUANTITY'),
			field: 'quantity'
		},
		{
			title: t('WAREHOUSE'),
			field: 'wareHouse'
		},
		{ title: t('STATUS'), field: 'status' },
		{
			title: t('REMARK'),
			field: 'remark',
			render: (rowData) => (
				<div style={{ display: 'flex', alignItems: 'center' }}>
					{rowData.remark}
					<InfoOutlinedIcon style={{ marginLeft: 8, fontSize: 15 }} />
				</div>
			)
		},
		{
			title: t('UNIT_PRICE'),
			field: 'unitPrice'
		},
		{
			title: t('TOTAL_PRICE'),
			field: 'totalPrice'
		},
		{
			title: t('ATTACH_DOCUMENT'),
			field: 'attachDocument',
			render: (rowData) => (
				<IconButton
					color="primary"
					onClick={() => handleAttachDocument(rowData)}
					style={{ display: 'flex', justifyContent: 'center', alignItems: 'center' }}
				>
					<AttachmentIcon style={{ fontSize: 30 }} />
				</IconButton>
			)
		}
	];

	const sampleData = [
		{
			claimId: 'CLM001',
			productId: 'PRD001',
			productName: 'Product A',
			size: 'Medium',
			quantity: 10,
			wareHouse: 'Warehouse 1',
			status: 'Pending',
			remark: 'First batch',
			unitPrice: 100,
			totalPrice: 1000,
			attachDocument: {
				link: 'link_to_document_1',
				images: [
					'https://www.thefishroom.net/cdn/shop/products/05_e21ba5fd-1acf-4ccd-ab3e-d6aa1f86dcee_1920x.jpg?v=1639750932',
					'data:image/jpeg;base64,',
					'data:image/jpeg;base64,',
					'data:image/webp;base64,'
				]
			}
		}
		// {
		// 	claimId: 'CLM002',
		// 	productId: 'PRD002',
		// 	productName: 'Product A',
		// 	size: 'Medium',
		// 	quantity: 20,
		// 	wareHouse: 'Warehouse 2',
		// 	status: 'Pending',
		// 	remark: 'First batch',
		// 	unitPrice: 200,
		// 	totalPrice: 2000,
		// 	attachDocument: {
		// 		link: 'link_to_document_2',
		// 		images: [
		// 			'data:image/jpeg;base64,',
		// 			'data:image/jpeg;base64,',
		// 			'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRvUSKC7K5MVgF04vPRd9PvJwRUQPogyXX1Aw&s',
		// 			'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSyW1yIiZEJqWHhNyxW1fe2kXuNxyJS60UrxA&s'
		// 		]
		// 	}
		// }
	];

	return (
		<div className="min-w-full max-w-[100vw]">
			<Grid
				container
				spacing={2}
			>
				<Grid
					item
					xs={12}
					className="pt-[5px!important]"
				>
					<h6 className="text-[12px] lg:text-[14px] text-primaryBlue font-600">Item Details</h6>
				</Grid>

				<Grid
					item
					xs={12}
					className="pt-[5px!important]"
				>
					<MaterialTableWrapper
						title=""
						filterChanged={null}
						handleColumnFilter={null}
						tableColumns={tableColumns}
						handlePageChange={handlePageChange}
						handlePageSizeChange={handlePageSizeChange}
						handleCommonSearchBar={null}
						pageSize={pageSize}
						disableColumnFiltering
						pageIndex={pageNo}
						setPageSize={setPageSize}
						searchByText=""
						disablePagination
						count={count}
						exportToExcel={null}
						handleRowDeleteAction={null}
						externalAdd={null}
						externalEdit={null}
						externalView={null}
						selection={false}
						disableSearch
						isColumnChoser
						records={sampleData}
					/>
				</Grid>
				<Grid
					item
					xs={12}
					className="pt-[15px!important]"
				>
					<hr />
				</Grid>
			</Grid>

			<Grid
				container
				spacing={2}
				className="mt-[5px]"
			>
				{isLoading ? (
					<Grid
						item
						xs={12}
						className="flex justify-center items-center"
					>
						<CircularProgress />
					</Grid>
				) : (
					images.map((image, index) => (
						<Grid
							item
							xs={3}
							key={index}
						>
							<img
								src={image}
								alt={`Image ${index + 1}`}
								style={{
									width: '100%',
									height: '100%',
									objectFit: 'cover',
									cursor: 'pointer',
									borderRadius: '8px'
								}}
								onClick={() => handleImageClick(image)}
							/>
						</Grid>
					))
				)}
			</Grid>

			<Grid
				container
				spacing={2}
				className="mt-[5px]"
			>
				<Grid
					item
					md={12}
					sm={12}
					xs={12}
					className="flex justify-end items-center gap-[10px] pt-[10px!important]"
				>
					<Button
						onClick={toggleModal}
						className="flex justify-center items-center min-w-[100px] min-h-[36px] max-h-[36px] text-[10px] sm:text-[12px] lg:text-[14px] text-gray-600 font-500 py-0 rounded-[6px] bg-gray-300 hover:bg-gray-300/80"
					>
						Close
					</Button>
				</Grid>
			</Grid>

			{/* Image Preview Modal */}
			<Dialog
				open={isPreviewOpen}
				onClose={closePreview}
				maxWidth="lg"
			>
				<DialogContent style={{ overflow: 'hidden' }}>
					<img
						src={selectedImage}
						alt="Preview"
						style={{ width: '100%', height: '100%', objectFit: 'contain' }}
					/>
				</DialogContent>
				<DialogActions>
					<Button
						onClick={closePreview}
						color="primary"
					>
						Close
					</Button>
				</DialogActions>
			</Dialog>
		</div>
	);
}

export default ClaimDetails;
